type TemplateData = Record<string, unknown>;

function resolvePath(data: TemplateData, path: string): unknown {
  return path.split(".").reduce<unknown>((value, key) => {
    if (value == null || typeof value !== "object") return undefined;
    return (value as Record<string, unknown>)[key];
  }, data);
}

function evaluateExpression(expression: string, data: TemplateData): unknown {
  const trimmed = expression.trim();

  if (!trimmed) return "";

  // Simple {{user.name}} style placeholders
  if (/^[A-Za-z_$][\w$]*(?:\.[A-Za-z_$][\w$]*)*$/.test(trimmed)) {
    return resolvePath(data, trimmed);
  }

  // Limited expression support, e.g. {{ user.name ?? "Guest" }}
  const keys = Object.keys(data);
  const values = keys.map((key) => data[key]);

  try {
    // eslint-disable-next-line no-new-func
    return new Function(...keys, `return (${trimmed});`)(...values);
  } catch {
    return "";
  }
}

export function renderTemplate(template: string, data: TemplateData): string {
  return template.replace(/\{\{([\s\S]+?)\}\}/g, (_match, expression: string) => {
    const value = evaluateExpression(expression, data);
    return value == null ? "" : String(value);
  });
}

