 * Render `{{...}}` placeholders from a data object.
 *
 * Supported forms:
 * - `{{name}}`
 * - `{{user.profile.name}}`
 * - `{{user.name || "Guest"}}`
 */
export function renderTemplate(template, data = {}) {
  return String(template).replace(/\{\{\s*([^}]+?)\s*\}\}/g, (_, expression) => {
    const value = resolveExpression(expression.trim(), data);
    return value == null ? "" : String(value);
  });
}

function resolveExpression(expression, data) {
  const parts = expression.split("||").map((part) => part.trim());

  for (const part of parts) {
    const value = resolvePath(part, data);
    if (value !== undefined && value !== null && value !== "") {
      return value;
    }

    const literal = parseLiteral(part);
    if (literal !== undefined) {
      return literal;
    }
  }

  return resolvePath(expression, data);
}

function resolvePath(path, data) {
  if (!path) return undefined;

  const segments = path.split(".");
  let current = data;

  for (const segment of segments) {
    if (current == null) return undefined;
    current = current[segment];
  }

  return current;
}

function parseLiteral(value) {
  if (value === "true") return true;
  if (value === "false") return false;
  if (value === "null") return null;
  if (value === "undefined") return undefined;

  if (/^-?\d+(\.\d+)?$/.test(value)) {
    return Number(value);
  }

  const quoted = value.match(/^(['"])(.*)\1$/);
  if (quoted) {
    return quoted[2];
  }

  return undefined;
}

