import { createHash } from 'crypto'

function toBodyBuffer(body: BodyInit | null): Promise<Buffer> {
  if (body == null) return Promise.resolve(Buffer.alloc(0))

  if (typeof body === 'string') return Promise.resolve(Buffer.from(body))
  if (body instanceof Buffer) return Promise.resolve(body)
  if (body instanceof Uint8Array) return Promise.resolve(Buffer.from(body))
  if (body instanceof ArrayBuffer) return Promise.resolve(Buffer.from(body))

  if (body instanceof ReadableStream) {
    return new Response(body).arrayBuffer().then((buf) => Buffer.from(buf))
  }

  return new Response(body).arrayBuffer().then((buf) => Buffer.from(buf))
}

function createETag(body: Buffer): string {
  return `"${createHash('md5').update(body).digest('hex')}"`
}

export const etag = (): MiddlewareHandler => {
  return async (c, next) => {
    await next()

    const response = c.res
    if (!response.ok || response.headers.has('ETag')) return

    const body = await toBodyBuffer(response.body)
    const etagValue = createETag(body)
    const ifNoneMatch = c.req.header('if-none-match')

    if (ifNoneMatch === etagValue) {
      c.res = new Response(null, {
        status: 304,
        headers: response.headers,
      })
      c.res.headers.set('ETag', etagValue)
      return
    }

    const headers = new Headers(response.headers)
    headers.set('ETag', etagValue)

    c.res = new Response(body, {
      status: response.status,
      statusText: response.statusText,
      headers,
    })
  }
}

