  // Identifiers resolve from `data`, numbers, strings, booleans, null,
  // arithmetic operators, comparisons, logical operators, parentheses,
  // member access, and array indexing.
  const allowed = /^[\w\s.+\-*/%<>=!&|?:()[\],"'`]+$/;
  if (!allowed.test(expr)) {
    throw new Error(`Disallowed characters in expression: ${expr}`);
  }

  const scope = new Proxy(data ?? {}, {
    has: () => true,
    get(target, key) {
      if (key === Symbol.unscopables) return undefined;
      return target[key];
    },
  });

  // Still uses eval internally, but only after strict filtering and with a
  // controlled scope. Avoid exposing globals.
  const fn = new Function(
    "scope",
    `
      with (scope) {
        return (${expr});
      }
    `
  );

  return fn(scope);
}

