export function evaluateTemplateFormula(template, data = {}) {
  if (typeof template !== 'string') {
    throw new TypeError('template must be a string');
  }

  const match = template.match(/^\s*\{\{\s*([\s\S]+?)\s*\}\}\s*$/);
  if (!match) return template;

  const expression = match[1];

  // Expose document data as local variables for the expression.
  const keys = Object.keys(data);
  const values = Object.values(data);

  // Intentionally uses eval() as requested.
  // Wrap in a Function so the context is controlled by explicit parameters.
  // The expression can reference fields like `price`, `quantity`, etc.
  const fn = new Function(...keys, `return (${expression});`);

  return fn(...values);
}

