type Token =
  | { type: "number"; value: number }
  | { type: "string"; value: string }
  | { type: "ident"; value: string }
  | { type: "op"; value: "+" | "-" | "*" | "/" | "(" | ")" | "." };

function tokenize(input: string): Token[] {
  const tokens: Token[] = [];
  let i = 0;

  while (i < input.length) {
    const ch = input[i];

    if (/\s/.test(ch)) {
      i++;
      continue;
    }

    if (/[0-9]/.test(ch) || (ch === "." && /[0-9]/.test(input[i + 1] ?? ""))) {
      const start = i;
      i++;
      while (i < input.length && /[0-9.]/.test(input[i])) i++;
      tokens.push({ type: "number", value: Number(input.slice(start, i)) });
      continue;
    }

    if (ch === "'" || ch === '"') {
      const quote = ch;
      i++;
      let out = "";
      while (i < input.length && input[i] !== quote) {
        if (input[i] === "\\" && i + 1 < input.length) {
          out += input[i + 1];
          i += 2;
        } else {
          out += input[i++];
        }
      }
      if (input[i] !== quote) throw new Error("Unterminated string literal");
      i++;
      tokens.push({ type: "string", value: out });
      continue;
    }

    if (/[A-Za-z_$]/.test(ch)) {
      const start = i;
      i++;
      while (i < input.length && /[A-Za-z0-9_$]/.test(input[i])) i++;
      tokens.push({ type: "ident", value: input.slice(start, i) });
      continue;
    }

    if ("+-*/().".includes(ch)) {
      tokens.push({ type: "op", value: ch as Token & { type: "op" }["value"] });
      i++;
      continue;
    }

    throw new Error(`Unexpected character: ${ch}`);
  }

  return tokens;
}

class Parser {
  private pos = 0;

  constructor(private tokens: Token[], private data: Context) {}

  parseExpression(): unknown {
    let left = this.parseTerm();
    while (this.matchOp("+") || this.matchOp("-")) {
      const op = this.previousOp();
      const right = this.parseTerm();
      left = op === "+" ? Number(left) + Number(right) : Number(left) - Number(right);
    }
    return left;
  }

  private parseTerm(): unknown {
    let left = this.parseFactor();
    while (this.matchOp("*") || this.matchOp("/")) {
      const op = this.previousOp();
      const right = this.parseFactor();
      left = op === "*" ? Number(left) * Number(right) : Number(left) / Number(right);
    }
    return left;
  }

  private parseFactor(): unknown {
    if (this.matchOp("-")) return -Number(this.parseFactor());
    if (this.matchOp("(")) {
      const value = this.parseExpression();
      this.expectOp(")");
      return value;
    }

    const token = this.advance();
    if (!token) throw new Error("Unexpected end of expression");

    if (token.type === "number" || token.type === "string") return token.value;
    if (token.type === "ident") return this.parseIdentifierChain(token.value);

    throw new Error(`Unexpected token: ${token.type}`);
  }

  private parseIdentifierChain(first: string): unknown {
    let value: unknown = this.data[first];

    while (this.matchOp(".")) {
      const next = this.advance();
      if (!next || next.type !== "ident") throw new Error("Expected property name after '.'");
      if (value == null || typeof value !== "object") return undefined;
      value = (value as Record<string, unknown>)[next.value];
    }

    return value;
  }

  private matchOp(op: Token["type"] extends "op" ? never : never): boolean;
  private matchOp(op: Token & { type: "op" }["value"]): boolean {
    const token = this.tokens[this.pos];
    if (token?.type === "op" && token.value === op) {
      this.pos++;
      return true;
    }
    return false;
  }

  private previousOp(): "+" | "-" | "*" | "/" {
    const token = this.tokens[this.pos - 1];
    if (!token || token.type !== "op" || !["+", "-", "*", "/"].includes(token.value)) {
      throw new Error("Expected operator");
    }
    return token.value as "+" | "-" | "*" | "/";
  }

  private expectOp(op: "(" | ")"): void {
    if (!this.matchOp(op)) throw new Error(`Expected '${op}'`);
  }

  private advance(): Token | undefined {
    return this.tokens[this.pos++];
  }

  expectEnd(): void {
    if (this.pos !== this.tokens.length) {
      throw new Error("Unexpected trailing tokens");
    }
  }
}

