import jsep from "jsep";

const OPS = {
  "+": (a, b) => a + b,
  "-": (a, b) => a - b,
  "*": (a, b) => a * b,
  "/": (a, b) => a / b,
  "%": (a, b) => a % b,
  "**": (a, b) => a ** b,
};

function resolveIdentifier(name, ctx) {
  if (!(name in ctx)) throw new Error(`Unknown variable: ${name}`);
  return ctx[name];
}

function evaluateAst(node, ctx) {
  switch (node.type) {
    case "Literal":
      return node.value;

    case "Identifier":
      return resolveIdentifier(node.name, ctx);

    case "BinaryExpression":
    case "LogicalExpression": {
      const left = evaluateAst(node.left, ctx);
      const right = evaluateAst(node.right, ctx);
      const op = OPS[node.operator];
      if (!op) throw new Error(`Unsupported operator: ${node.operator}`);
      return op(left, right);
    }

    case "UnaryExpression": {
      const value = evaluateAst(node.argument, ctx);
      if (node.operator === "+") return +value;
      if (node.operator === "-") return -value;
      throw new Error(`Unsupported unary operator: ${node.operator}`);
    }

    case "MemberExpression": {
      const object = evaluateAst(node.object, ctx);
      const property = node.computed
        ? evaluateAst(node.property, ctx)
        : node.property.name;

      if (object == null || !(property in object)) {
        throw new Error(`Unknown property: ${String(property)}`);
      }
      return object[property];
    }

    case "ConditionalExpression":
      return evaluateAst(node.test, ctx)
        ? evaluateAst(node.consequent, ctx)
        : evaluateAst(node.alternate, ctx);

    default:
      throw new Error(`Unsupported expression node: ${node.type}`);
  }
}

export function evaluateTemplateExpression(template, data) {
  const match = template.match(/^\s*\{\{(.+)\}\}\s*$/);
  if (!match) throw new Error("Invalid template expression");

  const expr = match[1].trim();
  const ast = jsep(expr);
  return evaluateAst(ast, data);
}

