const test = require("node:test");
const assert = require("node:assert/strict");
const { evaluateExpression, renderTemplate } = require("./formula-evaluator");

test("evaluates arithmetic using document context", () => {
  assert.equal(evaluateExpression("price * quantity", { price: 12.5, quantity: 4 }), 50);
});

test("supports template interpolation", () => {
  assert.equal(renderTemplate("Total: {{price * quantity}}", { price: 8, quantity: 3 }), "Total: 24");
});

test("supports parentheses and unary minus", () => {
  assert.equal(evaluateExpression("-(subtotal + tax) / 2", { subtotal: 8, tax: 2 }), -5);
});

test("resolves nested document paths", () => {
  assert.equal(
    evaluateExpression("customer.balance - payment", {
      customer: { balance: 100 },
      payment: 25,
    }),
    75
  );
});

test("rejects unknown identifiers", () => {
  assert.throws(() => evaluateExpression("process.exit()", {}));
});

